import { Box, Typography, Stack, ButtonBase, Button } from "@mui/material";
import axios from "../../utils/axios";
import api from "../../utils/api";
import Footer from "../../components/onboarding/footer";
import { useNavigate, useLocation } from "react-router";

import { updateFeedback } from "../../redux/actions/feedback";
import { useDispatch } from "react-redux";
import { updateOnboarding } from "../../redux/actions/Onboarding";
import Stepper from "../../components/progress";
import Image from "../../components/Image";
import Preview1 from "../../assets/onboarding/overview.svg";
import Preview2 from "../../assets/onboarding/overview2.svg";
import Preview3 from "../../assets/onboarding/overview3.svg";
import Iconify from "../../components/Iconify";
import Container from "../../components/Layout/Container";
import FooterBase from "../../components/Layout/Footer";
import Content from "../../components/Layout/Content";
import Header from "../../components/Layout/Header";
const RootStyle = styled("div")(() => ({
  display: "flex",
  flexDirection: "column",
  flex: 1,
  flexGrow: 1,
  height: "100vh",
}));

const BoxStyle = styled(Box)(() => ({
  position: "relative",
}));

const InsideBoxStyle = styled(Box)(() => ({
  position: "absolute",
  width: "100%",
  display: "flex",
  justifyContent: "center",
  alignItems: "center",
  flexDirection: "column",
  paddingTop: 52,
  paddingBottom: 24,
  zIndex: 100,
  top: 0,
}));

// ----------------------------------------------------------------------

export default function HomePage({mode}) {
  const dispatch = useDispatch();
  const { search } = useLocation();
  const { state } = useLocation();
  console.log(search);
  const query = new URLSearchParams(search);

  const slideData = {
    1: {
      image: Preview1,
      title: "Create your Profile",
      sub: "Show your expertise skills and achievements in your profile.",
    },
    2: {
      image: Preview2,
      title: "Build a fitness program",
      sub: "Create a fitness programs for clients to help achieve their goals.",
    },
    3: {
      image: Preview3,
      title: "Get paid",
      sub: "Monetize by selling your fitness program diffirent payment models.",
    },
  };
  const rePass =
    /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?])[A-Za-z\d!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]{8,}$/;

  const RegisterSchema = Yup.object().shape({
    email: Yup.string()
      .email("Email must be a valid email address")
      .required("Email is required"),
    password: Yup.string()
      .required("Password is required")

      .matches(
        rePass,
        "Minimum eight characters, at least one uppercase letter, one lowercase letter, one number and one special character"
      ),

    confirmPass: Yup.string()
      .required("confirm password is required")
      .oneOf([Yup.ref("password"), null], "Passwords must match"),
  });

  const formik = useFormik({
    initialValues: {
      email: "",
      password: "",
      confirmPass: "",
    },
    validationSchema: RegisterSchema,
    onSubmit: async (values, { setErrors, setSubmitting }) => {
      setSubmitting(true);
      dispatch(
        updateFeedback({
          loading: true,
        })
      );
      axios
        .post(`${api.protocol}${api.baseUrl}${api.SendVerifyMail}`, {
          email: values.email,
        })
        .then((response) => {
          dispatch(
            updateOnboarding({
              authType: 1,
              email: values.email,
              password: values.password,
              type: null,
            })
          );

          dispatch(
            updateFeedback({
              loading: false,
              snackbar: true,
              message: "Verification mail sent to your email!",
              severity: "success",
            })
          );
          navigate(`/onboarding/${mode=="client"?"client/":""}verification`, { state });
        })
        .catch((error) => {
          if (error.response.status === 406)
            return dispatch(
              updateFeedback({
                loading: false,
                snackbar: true,
                message: "Acccount with give email address already exists!",
                severity: "error",
              })
            );
          else
            return dispatch(
              updateFeedback({
                loading: false,
                snackbar: true,
                message: "Oops caught some error! Please try again",
                severity: "error",
              })
            );
        });
    },
  });
  const handelNext = () => {
    if (Number(query.get("slide")) == 3) {
      return navigate("/onboarding",{state});
    }
    navigate(
      "/onboarding/preview?slide=" +
        (query.get("slide") ? Number(query.get("slide")) + 1 : 2)
    );
  };
  const navigate = useNavigate();
  const {
    errors,
    touched,
    handleSubmit,
    isSubmitting,
    getFieldProps,
    setFieldValue,
    values,
  } = formik;
  return (
    <Page title="The starting point for your next fitness gig">
      <FormikProvider value={formik}>
        <Form autoComplete="off" noValidate onSubmit={handleSubmit}>
          <Container>
            <Header>
              <Box px={2} py={2}>
                <Stepper
                  handleClose={() => navigate("/",{state})}
                  steps={3}
                  active={Number(query.get("slide")) || 1}
                />
              </Box>
            </Header>
            <Content flex>
              <Box
                display={"flex"}
                flexDirection={"column"}
                alignItems={"center"}
                px={2}
                flexGrow={"1"}
              >
                <Box
                  display={"flex"}
                  flexDirection={"column"}
                  flexGrow={1}
                  sx={{ px: 2 }}
                  justifyContent={"center"}
                  width={"100%"}
                >
                  <Image
                    src={slideData?.[query.get("slide")]?.image || Preview1}
                  />
                  <Box width={"100%"} mt={6}>
                    <Typography variant="h2" textAlign={"center"}>
                      {slideData?.[query.get("slide")]?.title ||
                        slideData[1].title}
                    </Typography>
                    <Box sx={{ mt: 3 }}>
                      <Typography variant="body" align={"center"}>
                        <center>
                          {slideData?.[query.get("slide")]?.sub ||
                            slideData[1].sub}
                        </center>
                      </Typography>
                    </Box>
                  </Box>
                </Box>
              </Box>
            </Content>
            <FooterBase>
              <Box
                display={"flex"}
                justifyContent={"space-between"}
                width={"100%"}
                style={{ backgroundColor: "#fff" }}
                px={3}
                py={2}
              >
                <Button
                  variant=""
                  sx={{ color: "grey.500" }}
                  onClick={() => navigate(-1)}
                >
                  Back
                </Button>

                <Button
                  variant="contained"
                  sx={{
                    display: "flex",
                    justifyContent: "space-between",
                    minWidth: 132,
                  }}
                  onClick={handelNext}
                >
                  Next{" "}
                  <Iconify
                    icon={"akar-icons:circle-chevron-right"}
                    color="white"
                    width={20}
                    height={20}
                  />
                </Button>
              </Box>
            </FooterBase>
          </Container>
        </Form>
      </FormikProvider>
    </Page>
  );
}
